mapper.select:
left join mes_production_completion b on a.production_completion_id = b.id left join mes_job_assembly c on b.job_id = c.id left join mes_planned_production d on c.planned_production_id = d.id left join mes_production_plan e on d.production_plan_id = e.id left join mes_factory f on d.factory_id = f.id left join wms_material g on b.material_id = g.id left join mes_inspection_standards h on a.standards_id = h.id left join sys_user i on a.check_user_id = i.user_id
and a.serial_number like concat('%', #{serialNumber}, '%') and b.odd_numbers like concat('%', #{oddNumbers}, '%') and e.plan_number like concat('%', #{planNumber}, '%') and c.job_name like concat('%', #{jobName}, '%') and g.material_name like concat('%', #{materialName}, '%') and b.batch_number like concat('%', #{batchNumber}, '%') and d.manufacture_date between #{params.beginManufactureDate} and #{params.endManufactureDate} and h.check_item like concat('%', #{checkItem}, '%') and a.result = #{result} and a.check_user_id = #{checkUserId} and a.inspector_time between #{params.beginInspectorTime} and #{params.endInspectorTime}
order by a.id desc

mapper.update:
update mes_product_inspector
serial_number = #{serialNumber}, production_completion_id = #{productionCompletionId}, standards_id = #{standardsId}, sample_quantity = #{sampleQuantity}, inspection_value = #{inspectionValue}, result = #{result}, check_user_id = #{checkUserId}, inspector_time = #{inspectorTime}, remark = #{remark},
where id = #{id}
